fun solve(grid: Array<Array<Long>>, x: Long, y: Long, k: Long): Array<Array<Long>> {
    val xInt = x.toInt()
    val yInt = y.toInt()
    val kInt = k.toInt()

    // Create a copy of the grid to avoid modifying the original during processing
    val result = grid.map { it.clone() }.toTypedArray()

    for (i in 0 until kInt) {
        val row = xInt + i
        // Check if row is within bounds
        if (row >= grid.size) continue

        // Calculate the start and end columns for the current row
        val startCol = yInt
        val endCol = yInt + kInt - 1

        // Only proceed if startCol is within bounds
        if (startCol >= grid[row].size) continue

        // Determine the actual end column (may be less than yInt + kInt - 1 if out of bounds)
        val actualEndCol = minOf(endCol, grid[row].size - 1)

        // Perform the vertical flip for the current row segment
        var left = startCol
        var right = actualEndCol
        while (left < right) {
            val temp = result[row][left]
            result[row][left] = result[row][right]
            result[row][right] = temp
            left++
            right--
        }
    }

    return result
}
